hook.command:
.claude/hooks/pyrun -c "
import json, sys, os, re
d = json.load(sys.stdin)
ti = d.get('tool_input', {})
p = ti.get('file_path', '')
if not p or not p.endswith('.py'):
    sys.exit(0)
skip = ['test_', '_test.py', 'conftest', '__init__', 'alembic']
if any(s in os.path.basename(p).lower() for s in skip):
    sys.exit(0)
content = ti.get('content', '') or ti.get('new_string', '')
if not content:
    sys.exit(0)
imports = re.findall(r'(?:from)\s+([\w.]+)\s+import|(?:^import)\s+([\w.]+)', content, re.MULTILINE)
imports = [m[0] or m[1] for m in imports if m[0] or m[1]]
if not imports:
    sys.exit(0)
def has_layer(imp, keywords):
    return any(k in imp.lower() for k in keywords)
bn = os.path.basename(p).lower()
violations = []
if 'router' in bn or 'endpoint' in bn or 'route' in bn:
    for imp in imports:
        if has_layer(imp, ['repository', 'repositories', 'model', 'models']):
            if not has_layer(imp, ['schema', 'service']):
                violations.append(f'Router imports {imp} (should go through Service layer)')
elif 'service' in bn:
    for imp in imports:
        if has_layer(imp, ['router', 'endpoint', 'route']):
            violations.append(f'Service imports {imp} (routers depend on services, not vice versa)')
if violations:
    msg = '; '.join(violations[:2])
    print(json.dumps({'systemMessage': f'[BOUNDARY] {msg}. See coding-conventions.md Layer Boundaries.'}))
sys.exit(0)
"
